<script lang="ts">
  import type{QuarryState}from'$lib/game/quarry-match';
  export let state:QuarryState;export let label='Quarry Match board';export let compact=false;
  const mark:Record<string,string>={cyan:'◆',pink:'●',yellow:'✦',green:'▲',purple:'■'};
</script>
<div class="quarry-shell" class:compact aria-label={label} data-remaining={60-state.removed} data-cursor={state.cursor}>
  <div class="progress" aria-label="Current match group">{#each [0,1,2] as slot}<span class:filled={slot<state.groupCount} class:cyan={state.groupColor==='cyan'} class:pink={state.groupColor==='pink'} class:yellow={state.groupColor==='yellow'} class:green={state.groupColor==='green'} class:purple={state.groupColor==='purple'}>{slot<state.groupCount&&state.groupColor?mark[state.groupColor]:'·'}</span>{/each}</div>
  <div class="board">{#each state.columns as column,col}{#each Array(12) as _,visualRow}{@const color=column[11-visualRow]}<div class="cell" class:occupied={Boolean(color)} class:cyan={color==='cyan'} class:pink={color==='pink'} class:yellow={color==='yellow'} class:green={color==='green'} class:purple={color==='purple'}>{color?mark[color]:''}</div>{/each}<div class="cursor" class:selected={state.cursor===col}>▲</div>{/each}</div>
</div>
